def get_text(lang_code, key, **kwargs):
    """Retrieve translation based on language code and key"""
    # Standardize language code format
    if not lang_code:
        lang_code = "te-IN"
        
    code = str(lang_code).strip()
    
    # Handle language-only codes (e.g. 'te' -> 'te-IN')
    if code == "te":
        code = "te-IN"
    elif code == "en":
        code = "en-IN"
    elif code == "hi":
        code = "hi-IN"
    elif code == "es":
        code = "es-ES"
        
    if code not in TRANSLATIONS:
        code = "te-IN" # fallback
        
    text = TRANSLATIONS[code].get(key, TRANSLATIONS["te-IN"].get(key, ""))
    
    # Format if args are provided
    if kwargs:
        try:
            return text.format(**kwargs)
        except Exception:
            return text
            
    return text
